+    fn ext4_sync_with_logging(
+        &self,
+        cx: &Cx,
+        op: &str,
+        scenario_id: &'static str,
+        ino: InodeNumber,
+        datasync: bool,
+    ) -> ffs_error::Result<()> {
+        let operation_id = Self::ext4_sync_operation_id(op, ino, datasync);
+        let started = Instant::now();
+        info!(
+            target: "ffs::ext4::rw",
+            operation_id = %operation_id,
+            scenario_id,
+            outcome = "start",
+            ino = ino.0,
+            datasync,
+            "ext4_sync_start"
+        );
+
+        if !self.is_writable() {
+            warn!(
+                target: "ffs::ext4::rw",
+                operation_id = %operation_id,
+                scenario_id,
+                outcome = "rejected",
+                error_class = "read_only",
+                ino = ino.0,
+                datasync,
+                "ext4_sync_rejected"
+            );
+            return Err(FfsError::ReadOnly);
+        }
+
+        let duration_us = u64::try_from(started.elapsed().as_micros()).unwrap_or(u64::MAX);
+        match self.dev.sync(cx) {
+            Ok(()) => {
+                info!(
+                    target: "ffs::ext4::rw",
+                    operation_id = %operation_id,
+                    scenario_id,
+                    outcome = "applied",
+                    ino = ino.0,
+                    datasync,
+                    duration_us,
+                    "ext4_sync_applied"
+                );
+                Ok(())
+            }
+            Err(err) => {
+                warn!(
