+    c.bench_function("mount_runtime_per_core_route_inode", |b| {
+        let mut ino = 2_u64;
+        b.iter(|| {
+            let core = dispatcher.route_inode(black_box(ino));
+            ino = ino.wrapping_add(1);
+            black_box(core);
+        });
+    });
+}
